opencat.script:
// s1-canvas draw script — grid + radar + pulsing dot
const CK=ctx.CanvasKit;
const c=ctx.getCanvasById('s1-canvas');
const fill=(x)=>{const p=new CK.Paint();p.setStyle(CK.PaintStyle.Fill);p.setColor(CK.parseColorString(x));return p;};
const stroke=(x,w)=>{const p=new CK.Paint();p.setStyle(CK.PaintStyle.Stroke);p.setColor(CK.parseColorString(x));p.setStrokeWidth(w);return p;};
const t=ctx.frame/ctx.fps;
c.clear();
for(let i=0;i<8;i++){const y=80+i*80;const off=Math.sin(t*1.2+i*0.4)*30;c.drawLine(-40+off,y,1320+off,y,stroke('#38bdf833',1));}
c.save();c.translate(960,360);c.rotate(t*12);
for(let i=0;i<5;i++){c.drawCircle(0,0,60+i*30,stroke('#22d3ee44',2));}
c.restore();
c.drawCircle(960,360,20+Math.sin(t*3)*8,fill('#22d3ee'));

// scene1 — entrance animations
ctx.fromTo(['s1-kicker','s1-title','s1-desc'],{opacity:0,y:24},{opacity:1,y:0,stagger:6,duration:24,ease:'spring.gentle'});
ctx.fromTo(['s1-chip-1','s1-chip-2','s1-chip-3'],{opacity:0,scale:0.7},{opacity:1,scale:1,stagger:5,duration:20,ease:'spring.default'});
ctx.fromTo('s1-decor',{opacity:0,x:60},{opacity:1,x:0,duration:40,delay:6,ease:'spring.gentle'});

// scene2 — card grid entrance
ctx.fromTo(['s2-card-1','s2-card-2','s2-card-3','s2-card-4','s2-card-5','s2-card-6'],{opacity:0,y:30,scale:0.94},{opacity:1,y:0,scale:1,stagger:4,duration:22,ease:'spring.default'});
ctx.fromTo('s2-header',{opacity:0,x:-24},{opacity:1,x:0,duration:26,ease:'spring.gentle'});
ctx.fromTo('s2-preview',{opacity:0,scale:0.9},{opacity:1,scale:1,duration:28,delay:8,ease:'spring.default'});

// scene3 — video shell wobble + typewriter + thumbnails
ctx.to('s3-typewriter',{text:'Video plays live while the script overlay types this description frame by frame.',duration:72,delay:6,ease:'linear'});
ctx.to('s3-video-shell',{keyframes:{rotate:[{at:0,value:-6},{at:0.5,value:4,easing:'ease-in-out'},{at:1,value:0}],scale:[1,1.02,1]},duration:90});
ctx.fromTo(['s3-thumb-a','s3-thumb-b','s3-thumb-c'],{opacity:0,y:20,scale:0.9},{opacity:1,y:0,scale:1,stagger:4,duration:22,delay:24,ease:'spring.default'});
ctx.fromTo(['s3-kicker','s3-title'],{opacity:0,x:30},{opacity:1,x:0,duration:26,ease:'spring.gentle'});

// scene4 — orbs + metrics reveal
ctx.to('s4-orb',{keyframes:{rotate:[{at:0,value:0},{at:1,value:360}],scale:[{at:0,value:0.8},{at:0.5,value:1.15,easing:'ease-in-out'},{at:1,value:0.95}]},duration:90});
ctx.to('s4-orb-inner',{keyframes:{rotate:[{at:0,value:0},{at:1,value:-540}],y:[0,-20,0,20,0]},duration:90});
ctx.fromTo(['s4-title','s4-sub'],{opacity:0,y:30},{opacity:1,y:0,duration:28,ease:'spring.gentle'});
ctx.timeline().fromTo('s4-metric-1',{opacity:0,y:30,scale:0.92},{opacity:1,y:0,scale:1,duration:20,ease:'spring.default'}).fromTo('s4-metric-2',{opacity:0,y:30,scale:0.92},{opacity:1,y:0,scale:1,duration:20,ease:'spring.default'},'-=12').fromTo('s4-metric-3',{opacity:0,y:30,scale:0.92},{opacity:1,y:0,scale:1,duration:20,ease:'spring.default'},'-=12');
